        attrs
            .set(scope_attr, scope_val)
            .set(part_attr, part_val)
            .set(HtmlAttr::Id, self.ctx.ids.part("input"))
            .set(HtmlAttr::Type, "search")
            .set(HtmlAttr::Value, self.ctx.value.get().clone())
            .set(
